const body   = $input.first().json.body;
const userId = (body.user_id || '').trim();
const tags   = Array.isArray(body.tags) && body.tags.length > 0
  ? body.tags.map(t => String(t).trim()).filter(Boolean)
  : null;

if (!userId) {
  throw new Error('user_id is required');
}

const base = 'https://ipidfqwlszuhjgjygbvx.supabase.co/rest/v1/operator_memory';

// Build query string manually to control Supabase filter syntax precisely
const parts = [
  `user_id=eq.${encodeURIComponent(userId)}`,
  `select=${encodeURIComponent('id,memory_type,content,tags,created_at')}`,
  `order=created_at.desc`,
  `limit=20`
];

if (tags) {
  // Supabase array overlap operator: tags=ov.{tag1,tag2}
  // Uses PostgreSQL && (overlap) — matches rows where stored tags share any element
  parts.push(`tags=ov.%7B${tags.map(t => encodeURIComponent(t)).join(',')}%7D`);
}

return [{
  json: {
    query_url: `${base}?${parts.join('&')}`,
    user_id:    userId,
    has_tags:   tags !== null,
    tags_filter: tags || []
  }
}];

const raw  = $input.first().json;
const rows = Array.isArray(raw) ? raw : (raw && typeof raw === 'object' ? [raw] : []);

if (rows.length === 0) {
  return [{ json: { memories: '', count: 0, has_memories: false } }];
}

// Format each row: [memory_type] — content
// Ordered newest-first (as returned by Supabase order=created_at.desc)
const lines = rows.map(row => {
  const type    = (row.memory_type || 'fact').trim();
  const content = (row.content     || '').trim();
  const tagList = Array.isArray(row.tags) && row.tags.length > 0
    ? ` (tags: ${row.tags.join(', ')})`
    : '';
  return `[${type}] — ${content}${tagList}`;
});

const memories = `Past context:\n${lines.join('\n')}`;

return [{
  json: {
    memories,
    count:        rows.length,
    has_memories: true,
    raw_rows:     rows
  }
}];
